#!/usr/bin/env bash
set -euo pipefail

# Ali single-file spawner
# Public bootstrap artifact. Embedded defaults are non-secret.
# Usage:
#   bash spawn-ali.sh
# Optional overrides:
#   ALI_NODE_NAME=my-node ALI_PROFILE_NAME=ali-my-node bash spawn-ali.sh
#   ALI_WORKSPACE_DIR=$HOME/hermes-workspace bash spawn-ali.sh

RAW_NODE_NAME="${ALI_NODE_NAME:-$(hostname -s)}"
NODE_NAME="$(printf '%s' "$RAW_NODE_NAME" | tr '[:upper:]' '[:lower:]' | tr -c 'a-z0-9_-' '-')"
PROFILE_NAME="${ALI_PROFILE_NAME:-ali-$NODE_NAME}"
WORKSPACE_DIR="${ALI_WORKSPACE_DIR:-$HOME/hermes-workspace}"
HERMES_HOME_BASE="${HERMES_HOME_BASE:-$HOME/.hermes}"
PROFILE_DIR="$HERMES_HOME_BASE/profiles/$PROFILE_NAME"
ALI_DIR="$WORKSPACE_DIR/ali"
BOOTSTRAP_DIR="$ALI_DIR/bootstrap"
SHARED_SKILL_DIR="$ALI_DIR/shared/skills/ali-operating-model"
PROFILE_SKILL_DIR="$PROFILE_DIR/skills/custom/ali-operating-model"
SECRETS_FILE="$BOOTSTRAP_DIR/ali-secrets.local.env"
CONFIG_FILE="$BOOTSTRAP_DIR/config.current.yaml"
PROMPT_FILE="$ALI_DIR/NEW-NODE-PROMPT.md"
ARCH_FILE="$ALI_DIR/ALI-ARCHITECTURE.md"
BOOTSTRAP_MD_FILE="$ALI_DIR/NEW-NODE-BOOTSTRAP.md"
SKILL_FILE="$SHARED_SKILL_DIR/SKILL.md"

mkdir -p "$WORKSPACE_DIR" "$ALI_DIR" "$BOOTSTRAP_DIR" "$SHARED_SKILL_DIR" "$PROFILE_SKILL_DIR" "$PROFILE_DIR/memory" "$PROFILE_DIR/sessions" "$ALI_DIR/journal/$NODE_NAME" "$ALI_DIR/nodes/$NODE_NAME" "$ALI_DIR/knowledge" "$ALI_DIR/playbooks"

write_b64() {
  local target="$1"
  local payload="$2"
  python3 - "$target" "$payload" <<'PY'
import base64, pathlib, sys
path = pathlib.Path(sys.argv[1])
path.parent.mkdir(parents=True, exist_ok=True)
path.write_text(base64.b64decode(sys.argv[2]).decode())
PY
}

write_b64 "$SECRETS_FILE" ''
write_b64 "$CONFIG_FILE" ''
write_b64 "$SKILL_FILE" ''
write_b64 "$PROMPT_FILE" ''
write_b64 "$ARCH_FILE" ''
write_b64 "$BOOTSTRAP_MD_FILE" ''

chmod 600 "$SECRETS_FILE"
source "$SECRETS_FILE"

if command -v git >/dev/null 2>&1; then
  if [[ -n "${GITHUB_USERNAME:-}" ]]; then
    git config --global user.name "$GITHUB_USERNAME"
  fi
  if [[ -n "${GITHUB_EMAIL:-}" ]]; then
    git config --global user.email "$GITHUB_EMAIL"
  fi
  git config --global credential.helper store
  if [[ -n "${GITHUB_TOKEN:-}" && -n "${GITHUB_USERNAME:-}" ]]; then
    cat > "$HOME/.git-credentials" <<EOF
https://${GITHUB_USERNAME}:${GITHUB_TOKEN}@github.com
EOF
    chmod 600 "$HOME/.git-credentials"
  fi
fi

cp "$CONFIG_FILE" "$PROFILE_DIR/config.yaml"
cp "$SECRETS_FILE" "$PROFILE_DIR/.env"
cp "$SKILL_FILE" "$PROFILE_SKILL_DIR/SKILL.md"

if [[ ! -f "$WORKSPACE_DIR/.gitignore" ]]; then
  cat > "$WORKSPACE_DIR/.gitignore" <<'EOF'
.DS_Store
EOF
fi

if [[ ! -d "$WORKSPACE_DIR/.git" ]]; then
  if command -v git >/dev/null 2>&1; then
    git init "$WORKSPACE_DIR" >/dev/null 2>&1 || true
  fi
fi

if [[ ! -f "$ALI_DIR/nodes/$NODE_NAME/README.md" ]]; then
  cat > "$ALI_DIR/nodes/$NODE_NAME/README.md" <<EOF
# $NODE_NAME

- Hostname: $NODE_NAME
- Profile: $PROFILE_NAME
- Workspace: $WORKSPACE_DIR
- Initialized by: ali/spawn-ali.sh
EOF
fi

cat <<EOF

Ali spawn complete.

Profile:
  $PROFILE_NAME

Ali files:
  $ALI_DIR

Start Ali with:
  hermes --profile $PROFILE_NAME -s ali-operating-model

Then feed this file to the new session:
  $PROMPT_FILE

Optional next step if you want this node connected to the shared repo:
  cd "$WORKSPACE_DIR"
  git remote add origin "${ALI_REPO_PUSH_URL:-https://github.com/${ALI_REPO_OWNER:-bsccode}/${ALI_REPO_NAME:-hermes-workspace}.git}" 2>/dev/null || true
  git fetch origin || true
EOF
